from django.core.management.base import BaseCommand
from landingpages.models import LandingPage

LAYOUTS = ['default', 'minimal', 'showcase', 'cards', 'dark-hero', 'split', 'magazine', 'landing']

COLORS = [('#6366f1', '#a855f7'), ('#2563eb', '#06b6d4'), ('#059669', '#10b981'), ('#d97706', '#f59e0b'), ('#dc2626', '#f87171'), ('#7c3aed', '#c084fc'), ('#0891b2', '#22d3ee'), ('#be123c', '#fb7185'), ('#1d4ed8', '#60a5fa'), ('#0d9488', '#2dd4bf'), ('#b45309', '#fbbf24'), ('#4f46e5', '#818cf8')]

def assign_style(index):
    return {
        "layout": LAYOUTS[index % len(LAYOUTS)],
        "color_primary": COLORS[index % len(COLORS)][0],
        "color_accent": COLORS[index % len(COLORS)][1],
    }

PAGES = []
idx = 0
def p(data):
    global idx
    data.update(assign_style(idx))
    PAGES.append(data)
    idx += 1

